{"title":"Style a Neat Table Border","lesson":"L1 · HTML Foundations · HTML Tables","desc":"Use CSS to style the table borders. Add a dashed border style, make the borders collapse into single lines, and choose a border color for the table and cells 🎨","startFile":"css","goals":[{"id":"border-style","label":"Uses a dashed border style","target":"css","kind":"css_declaration","rule":"border-style\s*:\s*dashed","flags":"i","minCount":1},{"id":"border-collapse","label":"Collapses table borders","target":"css","kind":"css_declaration","rule":"border-collapse\s*:\s*collapse","flags":"i","minCount":1},{"id":"border-color","label":"Sets a border color","target":"css","kind":"css_declaration","rule":"border-color\s*:\s*[^;]+","flags":"i","minCount":1}],"targetHtml":"<div style="font-family:Arial,sans-serif;max-width:420px;">
  <h3 style="margin:0 0 10px;">Reading Log</h3>
  <table style="border-collapse:collapse;border:3px dashed teal;">
    <tr>
      <th style="border:3px dashed teal;padding:8px 12px;background:#eaf7f7;">Book</th>
      <th style="border:3px dashed teal;padding:8px 12px;background:#eaf7f7;">Pages</th>
    </tr>
    <tr>
      <td style="border:3px dashed teal;padding:8px 12px;">Space Cat</td>
      <td style="border:3px dashed teal;padding:8px 12px;">42</td>
    </tr>
    <tr>
      <td style="border:3px dashed teal;padding:8px 12px;">Jungle Map</td>
      <td style="border:3px dashed teal;padding:8px 12px;">30</td>
    </tr>
  </table>
</div>","targetSub":"A small table with dashed teal borders and joined border lines.","files":{"guide":{"html":"<h3>Reading Log</h3>
<table>
  <tr>
    <th>Book</th>
