    <td>42</td>
  </tr>
  <tr>
    <td>Jungle Map</td>
    <td>30</td>
  </tr>
</table>","css":"/* Style the whole page text so the table is easy to read. */
body {
  font-family: Arial, sans-serif;
}

/* The table needs collapsed borders so touching lines become one line. */
table {
  border-collapse: collapse;
  border-style: dashed;
  border-color: teal;
  border-width: 3px;
}

/* Give the cells matching borders and a little space inside. */
th,
td {
  border-style: dashed;
  border-color: teal;
  border-width: 3px;
  padding: 8px 12px;
}

/* A light background helps the heading cells stand out. */
th {
  background-color: #eaf7f7;
}","js":"// No JavaScript needed for this challenge."},"pair":{"html":"<h3>Reading Log</h3>
